CREATE TABLE `sexy_order_record` (
  `id` bigint NOT NULL COMMENT '主键ID',
  `platform_tx_id` varchar(64) DEFAULT NULL COMMENT '游戏商注单号',
  `user_id` varchar(64) DEFAULT NULL COMMENT '玩家帐号',
  `currency` varchar(8) DEFAULT NULL COMMENT '玩家使用的货币代码',
  `platform` varchar(64) DEFAULT NULL COMMENT '游戏平台名称',
  `game_type` varchar(32) DEFAULT NULL COMMENT '平台游戏类型',
  `game_code` varchar(64) DEFAULT NULL COMMENT '平台游戏代码',
  `game_name` varchar(128) DEFAULT NULL COMMENT '游戏名称',
  `bet_type` varchar(64) DEFAULT NULL COMMENT '游戏平台的下注项目',
  `bet_amount` decimal(22,4) DEFAULT NULL COMMENT '下注金额',
  `bet_time` bigint DEFAULT NULL COMMENT '玩家下注时间',
  `round_id` varchar(128) DEFAULT NULL COMMENT '游戏商的回合识别码',
  `game_info` json DEFAULT NULL COMMENT '游戏商提供的游戏信息，不验证内容',
  `is_premium` tinyint(1) DEFAULT NULL COMMENT '特殊收费游戏标记',
  `adjust_amount` decimal(22,4) DEFAULT NULL COMMENT '调整投注',
  `win_amount` decimal(22,4) DEFAULT NULL COMMENT '返还金额(包含下注金额)',
  `tip` decimal(22,4) DEFAULT NULL COMMENT '打赏金额',
  `turnover` decimal(22,4) DEFAULT NULL COMMENT '有效投注金额',
  `tx_time` varchar(64) DEFAULT NULL COMMENT '辨认交易时间依据-ISO8601',
  `update_time` bigint DEFAULT NULL COMMENT '注单更新时间',
  `ref_platform_tx_id` varchar(64) DEFAULT NULL COMMENT '用此注单号作为结算的参考',
  `settle_type` varchar(32) DEFAULT NULL COMMENT '结算方法',
  `venue_user_id` varchar(64) DEFAULT NULL COMMENT '三方账号id',
  `desk_no` varchar(64) DEFAULT NULL COMMENT '桌台号',
  `win_loss` decimal(22,4) DEFAULT NULL COMMENT '净输赢',
  `result_list` varchar(255) DEFAULT NULL COMMENT '结果牌',
  `winner` varchar(100) DEFAULT NULL COMMENT '赢家',
  `odds` varchar(20) DEFAULT NULL COMMENT '赔率',
  `ip` varchar(50) DEFAULT NULL COMMENT 'ip',
  `status` varchar(20) DEFAULT NULL COMMENT '订单状态 输/赢',
  `order_type` varchar(10) DEFAULT NULL COMMENT '订单类型 1-下注 2-取消下注 3-交易作废 4-结算 5-派彩取消 6-重派彩 7-打赏 8-取消打赏',
  PRIMARY KEY (`id`) /*T![clustered_index] CLUSTERED */
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='SEXY平台订单记录';


